//---------------------------------------------------------------------
// Globals
//---------------------------------------------------------------------
bool g_verbose           = false;
int  g_timing_iterations = 0;

// RAII wrapper for USM shared allocations
template <typename T>
struct UsmVector {
    T*           ptr  = nullptr;
    std::size_t  cap  = 0;       // allocated capacity (elements)
    std::size_t  sz   = 0;       // logical size (elements)
    sycl::queue& q;

    explicit UsmVector(sycl::queue& queue, std::size_t n = 0)
        : q(queue) {
        if (n) resize(n);
    }

    ~UsmVector() { free(); }

    // Non-copyable
    UsmVector(const UsmVector&)            = delete;
    UsmVector& operator=(const UsmVector&) = delete;

    void resize(std::size_t n) {
        if (n > cap) {
            free();
            ptr = sycl::malloc_shared<T>(n, q);
            if (!ptr) throw std::bad_alloc();
            cap = n;
        }
        sz = n;
    }

    void free() {
        if (ptr) { sycl::free(ptr, q); ptr = nullptr; cap = 0; sz = 0; }
    }

    T*       begin()       { return ptr; }
    T*       end()         { return ptr + sz; }
    const T* begin() const { return ptr; }
    const T* end()   const { return ptr + sz; }
    T&       operator[](std::size_t i)       { return ptr[i]; }
    const T& operator[](std::size_t i) const { return ptr[i]; }
    std::size_t size() const { return sz; }
};

template <typename T>
bool IsNaN(T /* val */) { return false; }

template<>
bool IsNaN<float>(float val)
{
  return std::isnan(val);
}

template<>
bool IsNaN<double>(double val)
{
  return std::isnan(val);
}

template <typename T>
T CoutCast(T val) { return val; }

inline int CoutCast(char val) { return val; }

inline int CoutCast(unsigned char val) { return val; }

inline int CoutCast(signed char val) { return val; }

template <typename InputIteratorT>
void DisplayResults(
    InputIteratorT h_data,
    std::size_t num_items)
{
    // Display data
    for (std::size_t i = 0; i < num_items; i++)
    {
        std::cout << CoutCast(h_data[i]) << ", ";
    }
    printf("\n");
}


// Initialize  — writes directly into a USM shared buffer (host-side, serial)
template <typename T>
void Initialize(int entropy_reduction, T* h_in, int num_items, int max_segment) {
    unsigned int max_int = std::numeric_limits<unsigned int>::max();
    int key = 0, i = 0;

    while (i < num_items) {
        int repeat;
        if (max_segment < 0) {
            repeat = num_items;
        } else if (max_segment < 2) {
            repeat = 1;
        } else {
            std::mt19937 mt(19937+i);
            std::uniform_int_distribution<int> dist(0, std::numeric_limits<int>::max());
            repeat = dist(mt);
            for (int n = 1; n <= entropy_reduction; n++) {
              repeat &= dist(mt);
            }
            repeat = (int)((double(repeat) * double(max_segment)) / double(max_int));
            repeat = std::max(1, repeat);
        }
        int end = std::min(i + repeat, num_items);
        for (int j = i; j < end; ++j)
            h_in[j] = static_cast<T>(key);
        i = end;
        ++key;
    }

    if (g_verbose) {
        std::printf("Input:\n");
        DisplayResults(h_in, num_items);
        std::printf("\n\n");
    }
}

// serial reference (reads/writes USM shared pointers on the host)
template <typename InputIt, typename T, typename OffsetT, typename LengthT>
int Solve(InputIt  h_in,
          T*       h_unique_ref,
          OffsetT* h_offsets_ref,
          LengthT* h_lengths_ref,
          int      num_items) {
    if (num_items == 0) return 0;

    T       previous  = h_in[0];
    LengthT length    = 1;
    int     num_runs  = 0;
    int     run_begin = 0;

    for (int i = 1; i < num_items; ++i) {
        if (previous != h_in[i]) {
            h_unique_ref [num_runs] = previous;
            h_offsets_ref[num_runs] = static_cast<OffsetT>(run_begin);
            h_lengths_ref[num_runs] = length;
            ++num_runs;
            length    = 1;
            run_begin = i;
        } else {
            ++length;
        }
        previous = h_in[i];
    }
    h_unique_ref [num_runs] = previous;
    h_offsets_ref[num_runs] = static_cast<OffsetT>(run_begin);
    h_lengths_ref[num_runs] = length;
    ++num_runs;

    return num_runs;
}

// ─────────────────────────────────────────────────────────────────────────────
// parallel_rle  — all three steps run on the SYCL device via oneDPL
//
//  All buffers are USM shared, allocated from the same queue as the policy.
//  The function returns the number of runs found.
//
//  Caller is responsible for pre-allocating unique_out, offsets_out,
//  lengths_out to at least N elements each (worst case).
//  On return, only [0, num_runs) of each output buffer is valid.
//
//  Steps
//  ─────
//  1. std::unique_copy   → unique values (one per run)
//  2. std::copy_if with head-flag predicate → run start offsets
//     Uses oneapi::dpl::counting_iterator to avoid a separate index buffer
//  3. std::adjacent_difference on offsets → inter-run deltas, then fixup
//     last run as  N - offsets[num_runs-1]
// ─────────────────────────────────────────────────────────────────────────────
template <typename Policy, typename T, typename OffsetT, typename LengthT>
int parallel_rle(Policy      exec,
                 const T*    in,
                 int         N,
                 T*          unique_out,
                 OffsetT*    offsets_out,
                 LengthT*    lengths_out,
                 OffsetT*    scratch)      // scratch buffer, N elements
{
    if (N == 0) return 0;

    // Step 1: unique values
    T* unique_end = std::unique_copy(exec, in, in + N, unique_out);
    int num_runs  = static_cast<int>(unique_end - unique_out);

    // Step 2: run-start offsets
    // copy_if over counting_iterator: keep index i where in[i] != in[i-1]
    // (or i == 0).  The lambda captures the raw USM pointer — valid on device
    // because the pointer was allocated via malloc_shared on the same queue.
    {
        using CntIt = oneapi::dpl::counting_iterator<int>;
        std::copy_if(exec,
                     CntIt(0), CntIt(N),
                     offsets_out,
                     [in](int idx) {
                         return idx == 0 || in[idx] != in[idx - 1];
                     });
        // Result: offsets_out[0..num_runs-1] are the run-start positions.
    }

    // Step 3: run lengths via adjacent_difference
    if (num_runs == 1) {
        lengths_out[0] = static_cast<LengthT>(N);
    } else {
        // adjacent_difference(offsets) → scratch
        // scratch[0]   = offsets[0]          (= 0, discard)
        // scratch[k]   = offsets[k]-offsets[k-1]  for k >= 1  → length of run k-1
        std::adjacent_difference(exec,
                                 offsets_out, offsets_out + num_runs,
                                 scratch);

        // lengths_out[k] = scratch[k+1]  for k in [0, num_runs-2]
        // lengths_out[num_runs-1] = N - offsets_out[num_runs-1]
        std::transform(exec,
                       scratch + 1, scratch + num_runs,
                       lengths_out,
                       [](OffsetT d) { return static_cast<LengthT>(d); });

        // Fixup last run: can be done on host; queue is already drained
        // because transform is synchronous under make_device_policy.
        lengths_out[num_runs - 1] =
            static_cast<LengthT>(N - offsets_out[num_runs - 1]);
    }

    return num_runs;
}

template <typename T, typename OffsetT, typename LengthT>
void Test(sycl::queue&   q,
          const T*       d_in,           // USM shared, N elements
          const T*       h_unique_ref,   // host or USM, num_runs_ref elements
          const LengthT* h_lengths_ref,  // host or USM, num_runs_ref elements
          int            num_runs_ref,
          int            num_items) {

    auto policy = oneapi::dpl::execution::make_device_policy(q);

    // Allocate USM output / scratch buffers (worst case = num_items each)
    UsmVector<T>       d_unique_out (q, num_items);
    UsmVector<OffsetT> d_offsets_out(q, num_items);
    UsmVector<LengthT> d_lengths_out(q, num_items);
    UsmVector<OffsetT> d_scratch    (q, num_items);  // adj_diff scratch

    // Warmup / correctness run
    int num_runs = parallel_rle(policy,
                                d_in,        num_items,
                                d_unique_out.ptr,
                                d_offsets_out.ptr,
                                d_lengths_out.ptr,
                                d_scratch.ptr);

    // USM shared: results are immediately visible on the host after the
    // oneDPL calls return (they are synchronous under make_device_policy).
    bool keys_ok = (num_runs == num_runs_ref) &&
                   std::equal(d_unique_out.ptr, d_unique_out.ptr + num_runs,
                              h_unique_ref);
    std::printf("\t Keys %s\n", keys_ok ? "PASS" : "FAIL");

    bool lens_ok = (num_runs == num_runs_ref) &&
                   std::equal(d_lengths_out.ptr, d_lengths_out.ptr + num_runs,
                              h_lengths_ref);
    std::printf("\t Lengths %s\n", lens_ok ? "PASS" : "FAIL");

    std::printf("\t Count %s\n", (num_runs == num_runs_ref) ? "PASS" : "FAIL");
    std::fflush(stdout);

    // Performance timing
    if (g_timing_iterations > 0) {
        auto t0 = std::chrono::steady_clock::now();
        for (int i = 0; i < g_timing_iterations; ++i) {
            parallel_rle(policy,
                         d_in,        num_items,
                         d_unique_out.ptr,
                         d_offsets_out.ptr,
                         d_lengths_out.ptr,
                         d_scratch.ptr);
        }
        auto t1 = std::chrono::steady_clock::now();
        double elapsed_ms = std::chrono::duration<double, std::milli>(t1 - t0).count();
        double avg_ms    = elapsed_ms / g_timing_iterations;
        double giga_rate = double(num_items) / avg_ms / 1e6;
        int    bytes     = (num_items * sizeof(T)) +
                           (num_runs  * (sizeof(OffsetT) + sizeof(LengthT)));
        double giga_bw   = double(bytes) / avg_ms / 1e6;
        std::printf(", %.3f avg ms, %.3f billion items/s, %.3f logical GB/s",
                    avg_ms, giga_rate, giga_bw);
    }
    std::printf("\n\n");
    std::fflush(stdout);
}

/**
 * Test DeviceRunLengthEncode on pointer type
 */
template <typename T, typename OffsetT, typename LengthT>
void TestPointer(sycl::queue& q, int num_items,
                 int entropy_reduction, int max_segment) {

    // All buffers are USM shared so both host (Initialize/Solve) and device
    // (parallel_rle) can access them without any explicit copies.
    UsmVector<T>       d_in         (q, num_items);
    UsmVector<T>       h_unique_ref (q, num_items);
    UsmVector<OffsetT> h_offsets_ref(q, num_items);
    UsmVector<LengthT> h_lengths_ref(q, num_items);

    std::fill(h_offsets_ref.ptr, h_offsets_ref.ptr + num_items,
              static_cast<OffsetT>(1));

    Initialize(entropy_reduction, d_in.ptr, num_items, max_segment);

    int num_runs = Solve(d_in.ptr,
                         h_unique_ref.ptr,
                         h_offsets_ref.ptr,
                         h_lengths_ref.ptr,
                         num_items);

    std::printf("\nTest pointer: %d items, %d segments (avg run length %.3f), "
                "{%s key, %s offset, %s length}, max_segment %d, "
                "entropy_reduction %d\n",
                num_items, num_runs,
                float(num_items) / float(num_runs),
                typeid(T).name(), typeid(OffsetT).name(), typeid(LengthT).name(),
                max_segment, entropy_reduction);
    std::fflush(stdout);

    Test<T, OffsetT, LengthT>(q,
                              d_in.ptr,
                              h_unique_ref.ptr,
                              h_lengths_ref.ptr,
                              num_runs,
                              num_items);
}

/**
 * Test on iterator type
 */
template <typename T, typename OffsetT, typename LengthT>
void TestIterator(sycl::queue& q, int num_items) {
    UsmVector<T>       d_in         (q, num_items);
    UsmVector<T>       h_unique_ref (q, num_items);
    UsmVector<OffsetT> h_offsets_ref(q, num_items);
    UsmVector<LengthT> h_lengths_ref(q, num_items);

    // Fill with constant value 1
    std::fill(d_in.ptr, d_in.ptr + num_items, static_cast<T>(1));

    int num_runs = Solve(d_in.ptr,
                         h_unique_ref.ptr,
                         h_offsets_ref.ptr,
                         h_lengths_ref.ptr,
                         num_items);

    std::printf("\nTest iterator: on %d items, %d segments (avg run length %.3f), "
                "{%s key, %s offset, %s length}\n",
                num_items, num_runs,
                float(num_items) / float(num_runs),
                typeid(T).name(), typeid(OffsetT).name(), typeid(LengthT).name());
    std::fflush(stdout);

    Test<T, OffsetT, LengthT>(q,
                              d_in.ptr,
                              h_unique_ref.ptr,
                              h_lengths_ref.ptr,
                              num_runs,
                              num_items);
}

template <typename T, typename OffsetT, typename LengthT>
void TestAll(sycl::queue& q, int num_items) {

    // Test iterator (one run)
    TestIterator<T, OffsetT, LengthT>(q, num_items);

    // Evaluate different run lengths / segment sizes
    const int max_seg_limit = std::min(num_items, 1 << 16);
    const int max_seg_inc   = 4;
    for (int max_segment = 1, entropy_reduction = 0; max_segment <= max_seg_limit;
        max_segment <<= max_seg_inc, ++entropy_reduction) {
        const int max_seg = std::max(1, max_segment);
        TestPointer<T, OffsetT, LengthT>(q, num_items, entropy_reduction, max_seg);
    }
}

/**
 * Test different dispatch
 */
template <typename T, typename OffsetT, typename LengthT>
void TestDispatch(sycl::queue& q, int num_items) {
    TestAll<T, OffsetT, LengthT>(q, num_items);
}

template <typename T, typename OffsetT, typename LengthT>
void TestSize(sycl::queue& q, int num_items) {
    if (num_items < 0)
    {
        //TestDispatch<T, OffsetT, LengthT>(q, 1);
        //TestDispatch<T, OffsetT, LengthT>(q, 100);
        //TestDispatch<T, OffsetT, LengthT>(q, 10000);
        TestDispatch<T, OffsetT, LengthT>(q, 1000000);
    }
    else
    {
        TestDispatch<T, OffsetT, LengthT>(q, num_items);
    }
}

//---------------------------------------------------------------------
// Main
//---------------------------------------------------------------------
int main(int argc, char** argv) {
    int num_items = -1;

    for (int i = 1; i < argc; ++i) {
        std::string arg(argv[i]);
        if      (arg.rfind("--n=", 0) == 0) num_items = std::stoi(arg.substr(4));
        else if (arg.rfind("--i=", 0) == 0) g_timing_iterations = std::stoi(arg.substr(4));
        else if (arg == "-v" || arg == "--v") g_verbose = true;
        else if (arg == "--help") {
            std::printf("%s [--n=<input items>] [--i=<timing iterations>] [--v]\n",
                        argv[0]);
            return 0;
        }
    }

    // Create SYCL queue
#ifdef USE_GPU
    sycl::queue q(sycl::gpu_selector_v, sycl::property::queue::in_order());
#else
    sycl::queue q(sycl::cpu_selector_v, sycl::property::queue::in_order());
#endif

    // Test different input types
    // TestSize<signed char, int, int>(q, num_items);
    // TestSize<short,       int, int>(q, num_items);
    TestSize<int,         int, int>(q, num_items);
    // TestSize<long,        int, int>(q, num_items);
    // TestSize<long long,   int, int>(q, num_items);
    // TestSize<float,       int, int>(q, num_items);
    // TestSize<double,      int, int>(q, num_items);

    return 0;
}

